 1→import type { IngestSessionInput } from "@rudel/api-routes";
 2→import {
 3→	type Ingestor,
 4→	ingestRudelClaudeSessions,
 5→	type RudelClaudeSessionsRow,
 6→} from "@rudel/ch-schema/generated";
 7→
 8→interface IngestContext {
 9→	userId: string;
10→	organizationId: string;
11→}
12→
13→export function extractTimestampRange(content: string): {
14→	sessionDate: string;
15→	lastInteractionDate: string;
16→} | null {
17→	let min: string | null = null;
18→	let max: string | null = null;
19→
20→	for (const line of content.split("\n")) {
21→		if (!line) continue;
22→		let parsed: { type?: string; timestamp?: string };
23→		try {
24→			parsed = JSON.parse(line);
25→		} catch {
26→			continue;
27→		}
28→		if (
29→			(parsed.type === "user" || parsed.type === "assistant") &&
30→			parsed.timestamp
31→		) {
32→			const ts = parsed.timestamp;
33→			if (!min || ts < min) min = ts;
34→			if (!max || ts > max) max = ts;
35→		}
36→	}
37→
38→	if (!min || !max) return null;
39→
40→	return { sessionDate: min, lastInteractionDate: max };
41→}
42→
43→function toClickHouseDateTime(isoString: string): string {
44→	return isoString.replace("T", " ").replace("Z", "").replace(/\+.*$/, "");
45→}
46→
47→export function buildSessionRow(
48→	input: IngestSessionInput,
49→	context: IngestContext,
50→): RudelClaudeSessionsRow {
51→	const now = new Date().toISOString().replace("Z", "");
52→
53→	const subagents: Record<string, string> = {};
54→	if (input.subagents) {
55→		for (const sub of input.subagents) {
56→			subagents[sub.agentId] = sub.content;
57→		}
58→	}
59→
60→	const timestamps = extractTimestampRange(input.content);
61→
62→	return {
63→		session_date: timestamps
64→			? toClickHouseDateTime(timestamps.sessionDate)
65→			: now,
66→		last_interaction_date: timestamps
67→			? toClickHouseDateTime(timestamps.lastInteractionDate)
68→			: now,
69→		session_id: input.sessionId,
70→		organization_id: context.organizationId,
71→		project_path: input.projectPath,
72→		repository: input.repository ?? null,
73→		content: input.content,
74→		subagents,
75→		ingested_at: now,
76→		user_id: context.userId,
77→		git_branch: input.gitBranch ?? null,
78→		git_sha: input.gitSha ?? null,
79→		tag: input.tag ?? null,
80→	};
81→}
82→
83→export async function ingestSession(
84→	ingestor: Ingestor,
85→	input: IngestSessionInput,
86→	context: IngestContext,
87→): Promise<void> {
88→	const row = buildSessionRow(input, context);
89→	await ingestRudelClaudeSessions(ingestor, [row]);
90→}
