 25→const trustedOrigins = process.env.TRUSTED_ORIGINS
 26→	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 27→	: ["http://localhost:4011"];
 28→
 29→const auth = createAuth(db, {
 30→	appURL,
 31→	secret: process.env.BETTER_AUTH_SECRET,
 32→	socialProviders,
 33→	trustedOrigins,
 34→	slackWebhookUrl: process.env.SLACK_WEBHOOK_URL,
 35→});
 36→
 37→const rpcHandler = new RPCHandler(router);
 38→
 39→const ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 40→const STATIC_DIR = join(
 41→	import.meta.dir,
 42→	"..",
 43→	process.env.STATIC_DIR ?? "public",
 44→);
 45→
 46→function corsHeaders(origin: string | null): Record<string, string> {
 47→	if (origin !== ALLOWED_ORIGIN) return {};
 48→	return {
 49→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 50→		"Access-Control-Allow-Credentials": "true",
 51→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 52→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 53→	};
 54→}
 55→
 56→const port = process.env.PORT ?? 4010;
 57→
 58→const server = Bun.serve({
 59→	port,
 60→	async fetch(request) {
 61→		const origin = request.headers.get("Origin");
 62→		const cors = corsHeaders(origin);
 63→
 64→		if (request.method === "OPTIONS") {
 65→			return new Response(null, { status: 204, headers: cors });
 66→		}
 67→
 68→		const url = new URL(request.url);
 69→
 70→		// Health check for Fly.io (must be GET-accessible)
 71→		if (url.pathname === "/health") {
 72→			return Response.json({ status: "ok", timestamp: Date.now() });
 73→		}
 74→
 75→		if (url.pathname === "/api/cli-token") {
 76→			const session = await auth.api.getSession({
 77→				headers: request.headers,
 78→			});
 79→			if (!session) {
 80→				return new Response(JSON.stringify({ error: "Not authenticated" }), {
 81→					status: 401,
 82→					headers: { ...cors, "Content-Type": "application/json" },
 83→				});
 84→			}
 85→			return new Response(JSON.stringify({ token: session.session.token }), {
 86→				status: 200,
 87→				headers: { ...cors, "Content-Type": "application/json" },
 88→			});
 89→		}
 90→
 91→		if (url.pathname.startsWith("/api/auth")) {
 92→			const response = await auth.handler(request);
 93→			for (const [key, value] of Object.entries(cors)) {
 94→				response.headers.set(key, value);
 95→			}
 96→			return response;
 97→		}
 98→
 99→		const { matched, response } = await rpcHandler.handle(request, {
100→			prefix: "/rpc",
101→			context: await getContext(request),
102→		});
103→
104→		if (matched) {
105→			// Log 500 errors for debugging
106→			if (response.status >= 500) {
107→				const body = await response.clone().text();
108→				console.error(`[RPC ${url.pathname}] ${response.status}:`, body);
109→			}
110→			for (const [key, value] of Object.entries(cors)) {
111→				response.headers.set(key, value);
112→			}
113→			return response;
114→		}
115→
116→		// Static file serving (production: frontend assets)
117→		const filePath = join(STATIC_DIR, url.pathname);
118→		const file = Bun.file(filePath);
119→		if (await file.exists()) {
120→			return new Response(file);
121→		}
122→
123→		// SPA fallback: serve index.html for non-API routes
124→		const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
125→		if (await indexFile.exists()) {
126→			return new Response(indexFile);
127→		}
128→
129→		// Dev mode: redirect to frontend dev server for non-API routes
130→		// (e.g., after OAuth callback redirects to APP_URL which has no SPA)
131→		if (ALLOWED_ORIGIN !== appURL) {
132→			return Response.redirect(
133→				`${ALLOWED_ORIGIN}${url.pathname}${url.search}`,
134→				302,
135→			);
136→		}
137→
138→		return new Response("Not found", { status: 404, headers: cors });
139→	},
140→});
